func ParseIntHTTP(v interface{}) int {
	if v == nil {
		return 0
	}
	switch val := v.(type) {
	case string:
		parsed, _ := strconv.Atoi(val)
		return parsed
	case float64:
		return int(val)
	case int:
		return val
	case int64:
		return int(val)
	default:
		return 0
	}
}

